// Command alpkernels generates per-width fused unpack+decode kernels for the
// ALP-main decoder. Each kernel decodes full 8-value groups of w-bit codes
// (which are byte-aligned: 8*w bits == w bytes exactly) straight from bit 0
// into a float64 slice, using compile-time-constant shifts and masks so the Go
// compiler emits straight-line loads with the interior bounds checks removed.
//
// The emitted file is deterministic (no timestamps, widths walked in order) and
// carries the "Code generated ... DO NOT EDIT." header so golangci-lint treats
// it as generated. Invoked by the //go:generate directive in alp.go:
//
//	go run ./gen/alpkernels
//
// Optional first argument overrides the output path (default
// numeric_alp_kernels_gen.go in the current directory).
package main

import (
	"fmt"
	"go/format"
	"log"
	"os"
	"strings"
)

const minWidth = 1
const maxWidth = 64

func main() {
	out := "numeric_alp_kernels_gen.go"
	if len(os.Args) > 1 {
		out = os.Args[1]
	}

	src := generate()
	formatted, err := format.Source([]byte(src))
	if err != nil {
		log.Fatalf("alpkernels: gofmt failed: %v\n----\n%s", err, src)
	}
	if err := os.WriteFile(out, formatted, 0o644); err != nil { //nolint:gosec // generated Go source, world-readable is fine
		log.Fatalf("alpkernels: write %s: %v", out, err)
	}
}

// generate returns the full source of numeric_alp_kernels_gen.go.
func generate() string {
	var sb strings.Builder
	p := func(s string) { sb.WriteString(s) }

	p("// Code generated by gen/alpkernels; DO NOT EDIT.\n\n")
	p("package alp\n\n")
	p("import \"encoding/binary\"\n\n")
	p("// alpFusedUnpack[w] decodes n w-bit ALP-main codes (n a multiple of 8),\n")
	p("// bit-packed LSB-first from bit 0 of codes, into dst[:n] as\n")
	p("// float64(int64(code)+mn) * pf * ie — the exact scalar decode of\n")
	p("// decodeMainInto, fused so unpack, FOR-add, and scale happen in one pass.\n")
	p("// Index 0 (and any width without a kernel) is nil: the caller falls back to\n")
	p("// the scalar loop. Each kernel consumes 8 values per iteration from the\n")
	p("// byte-aligned group window codes[g*w : g*w+8*ceil(w/8)]; the caller must\n")
	p("// only pass an n whose groups stay within codes (see decodeMainInto).\n")
	p("var alpFusedUnpack = [65]func(codes []byte, n int, mn int64, pf, ie float64, dst []float64){\n")
	for w := minWidth; w <= maxWidth; w++ {
		p(fmt.Sprintf("\t%d: alpUnpackW%d,\n", w, w))
	}
	p("}\n")

	for w := minWidth; w <= maxWidth; w++ {
		p("\n")
		p(genKernel(w))
	}

	p("\n// alpUnpackBits[w] unpacks n w-bit codes (n a multiple of 8), bit-packed\n")
	p("// LSB-first from bit 0 of codes, into dst[:n] as raw uint64 values — pure\n")
	p("// unpack, no arithmetic (unlike alpFusedUnpack above). Used by\n")
	p("// decodeRDInto's two-stream bulk unpack: one call at width codeBits for\n")
	p("// the left dictionary codes, one call at width rbw for the right parts.\n")
	p("// Index 0 (and any width without a kernel) is nil: the caller falls back\n")
	p("// to the scalar per-value loop. Same byte-aligned group / over-read\n")
	p("// contract as alpFusedUnpack — the caller must only pass an n whose\n")
	p("// groups stay within codes (see decodeRDInto).\n")
	p("var alpUnpackBits = [65]func(codes []byte, n int, dst []uint64){\n")
	for w := minWidth; w <= maxWidth; w++ {
		p(fmt.Sprintf("\t%d: alpUnpackBitsW%d,\n", w, w))
	}
	p("}\n")

	for w := minWidth; w <= maxWidth; w++ {
		p("\n")
		p(genUnpackKernel(w))
	}

	return sb.String()
}

// genUnpackKernel emits one width-w pure-unpack kernel: same group/word-load
// structure as genKernel, but stores the extracted raw uint64 code directly
// (no FOR-add/scale arithmetic). Reuses extract() so the exact same
// shift/mask expression that is proven byte-exact for alpFusedUnpack backs
// this table too.
func genUnpackKernel(w int) string {
	nwords := (w + 7) / 8
	chunk := nwords * 8

	var sb strings.Builder
	p := func(s string) { sb.WriteString(s) }

	p(fmt.Sprintf("func alpUnpackBitsW%d(codes []byte, n int, dst []uint64) {\n", w))
	p("\tgroups := n >> 3\n")
	p("\tfor g := 0; g < groups; g++ {\n")
	p(fmt.Sprintf("\t\tbase := g * %d\n", w))
	p(fmt.Sprintf("\t\tb := (*[%d]byte)(codes[base:])\n", chunk))
	for j := 0; j < nwords; j++ {
		p(fmt.Sprintf("\t\tw%d := binary.LittleEndian.Uint64(b[%d:%d])\n", j, j*8, j*8+8))
	}
	p("\t\td := (*[8]uint64)(dst[g<<3:])\n")
	for k := 0; k < 8; k++ {
		p(fmt.Sprintf("\t\td[%d] = %s\n", k, extract(w, k)))
	}
	p("\t}\n")
	p("}\n")

	return sb.String()
}

// genKernel emits one width-w kernel. It loads the ceil(w/8) 64-bit words that
// cover a group once, then extracts each of the 8 values with constant shifts
// (and a constant two-word stitch when a value straddles a 64-bit boundary).
func genKernel(w int) string {
	nwords := (w + 7) / 8 // ceil(w/8): 64-bit words spanning one 8-value group
	chunk := nwords * 8   // bytes the group window reslice must cover

	var sb strings.Builder
	p := func(s string) { sb.WriteString(s) }

	p(fmt.Sprintf("func alpUnpackW%d(codes []byte, n int, mn int64, pf, ie float64, dst []float64) {\n", w))
	p("\tgroups := n >> 3\n")
	p("\tfor g := 0; g < groups; g++ {\n")
	p(fmt.Sprintf("\t\tbase := g * %d\n", w))
	// One bounds check per group at each array-pointer conversion; every interior
	// load/store is then a constant index into a fixed-size array, so the compiler
	// drops all interior bounds checks. The conversion panics iff the group window
	// codes[base:base+chunk] would run past codes — the caller sizes n so it can't.
	p(fmt.Sprintf("\t\tb := (*[%d]byte)(codes[base:])\n", chunk))
	for j := 0; j < nwords; j++ {
		p(fmt.Sprintf("\t\tw%d := binary.LittleEndian.Uint64(b[%d:%d])\n", j, j*8, j*8+8))
	}
	p("\t\td := (*[8]float64)(dst[g<<3:])\n")
	for k := 0; k < 8; k++ {
		p(fmt.Sprintf("\t\td[%d] = float64(int64(%s)+mn) * pf * ie\n", k, extract(w, k)))
	}
	p("\t}\n")
	p("}\n")

	return sb.String()
}

// extract returns the Go expression yielding value k (0..7) of a group as a
// uint64, using constant shifts/masks derived from width w. All indices/shifts
// are compile-time constants.
func extract(w, k int) string {
	lobit := k * w
	sh := lobit & 63
	wlo := lobit >> 6
	hibit := lobit + w - 1
	whi := hibit >> 6

	if w == 64 {
		// One value per word, no shift, no mask (int64(code) matches the scalar
		// int64(code) full-width conversion).
		return fmt.Sprintf("w%d", wlo)
	}

	mask := (uint64(1) << uint(w)) - 1
	maskLit := fmt.Sprintf("0x%x", mask)

	if whi == wlo {
		// Value lives entirely in one word.
		if sh == 0 {
			return fmt.Sprintf("w%d&%s", wlo, maskLit)
		}

		return fmt.Sprintf("(w%d>>%d)&%s", wlo, sh, maskLit)
	}

	// Value straddles the 64-bit boundary between word wlo and word wlo+1; sh is
	// necessarily >= 1 here, so 64-sh is in [1,63].
	return fmt.Sprintf("((w%d>>%d)|(w%d<<%d))&%s", wlo, sh, whi, 64-sh, maskLit)
}
